  if (context === asyncLocalStorage.getStore()?.contextId) {
    console.log(`Async operation ${asyncId} (${operationName}) is triggered by async operation ${triggerAsyncId}`);
  }
}

// Create a function that uses AsyncHooks
async function doSomethingAsync() {
  // Create an AsyncHooks instance inside the function
  const asyncHook = async_hooks.createHook({
    init: initCallback
  });

  // Enable the AsyncHooks instance
  asyncHook.enable();

  // Run some async code
  await new Promise(resolve => setTimeout(() => resolve(), 100));

  // Disable the AsyncHooks instance
  asyncHook.disable();
}

// Helper function to get resource name
function getResourceName(resource) {
  if (typeof resource === "object" && resource.constructor && resource.constructor.name) {
    return resource.constructor.name;
  } else if (typeof resource === "function") {
    return resource.name || "Function";
  }
  return "unknown";
}

// Run some async code with AsyncLocalStorage
asyncLocalStorage.run({contextId: async_hooks.executionAsyncId()}, async () => {
  await doSomethingAsync();
});
